<div class="page-title-row"><div><span class="text-muted">Mobile and trusted integration foundation</span><h1>API Access</h1></div><a class="btn btn-outline-primary" href="/portal/api/analytics"><i class="fa-solid fa-chart-column me-2"></i>Usage analytics</a></div><?php if(!empty($_SESSION['_new_api_token'])):$new=$_SESSION['_new_api_token'];unset($_SESSION['_new_api_token']);?><div class="alert alert-warning"><strong>Copy this token now:</strong><div class="font-monospace text-break mt-2"><?=e($new)?></div></div><?php endif?><div class="row g-4"><div class="col-lg-4"><div class="portal-card p-4"><h2>Create token</h2><form method="post" action="/portal/api/tokens" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Name</label><input class="form-control" name="name" required></div><div class="col-12"><label class="form-label">User</label><select class="form-select" name="user_id"><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Abilities</label><input class="form-control" name="abilities" value="customers.read,jobs.read"><div class="form-text">Comma-separated. Write endpoints require <code>customers.write</code> or <code>jobs.write</code>. Use <code>*</code> only for tightly controlled integrations.</div></div><div class="col-12"><label class="form-label">Expires</label><input class="form-control" type="datetime-local" name="expires_at"></div><div class="col-12"><button class="btn btn-primary">Create token</button></div></form></div><div class="portal-card p-4 mt-4"><h3 class="h5">Read endpoints</h3><code>GET /api/v1/me</code><br><code>GET /api/v1/jobs/today</code><br><code>GET /api/v1/customers</code><br><code>GET /api/v1/health</code><h3 class="h5 mt-4">Write endpoints</h3><code>POST /api/v1/customers</code><br><code>POST /api/v1/jobs/{id}/status</code><br><code>POST /api/v1/jobs/{id}/notes</code></div></div><div class="col-lg-8"><div class="portal-card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Name</th><th>User</th><th>Abilities</th><th>Last used</th><th>Expires</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($tokens as $t):?><tr><td><?=e($t['name'])?></td><td><?=e($t['user_name'])?></td><td><code><?=e($t['abilities_json'])?></code></td><td><?=e($t['last_used_at'])?></td><td><?=e($t['expires_at'])?></td><td><?=$t['revoked_at']?'Revoked':'Active'?></td><td><?php if(!$t['revoked_at']):?><form method="post" action="/portal/api/tokens/<?=$t['id']?>/revoke"><?=csrf_field()?><button class="btn btn-sm btn-outline-danger">Revoke</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
<div class="portal-card mt-4"><div class="card-header-row"><div><h2>Quota administration</h2><p>Adjust daily and monthly request limits and warning thresholds.</p></div></div><div class="table-responsive"><table class="table portal-table align-middle"><thead><tr><th>Token</th><th>Daily</th><th>Monthly</th><th>Warning</th><th></th></tr></thead><tbody><?php foreach($tokens as $t):?><tr><form method="post" action="/portal/api/tokens/<?=$t['id']?>/quota"><?=csrf_field()?><td><strong><?=e($t['name'])?></strong><div class="small text-muted"><?=e($t['user_name'])?></div></td><td><input class="form-control form-control-sm" type="number" min="1" name="daily_quota" value="<?=e($t['daily_quota']??600)?>"></td><td><input class="form-control form-control-sm" type="number" min="1" name="monthly_quota" value="<?=e($t['monthly_quota']??10000)?>"></td><td><div class="input-group input-group-sm"><input class="form-control" type="number" min="10" max="100" name="quota_warning_percent" value="<?=e($t['quota_warning_percent']??80)?>"><span class="input-group-text">%</span></div></td><td><button class="btn btn-sm btn-outline-primary">Save</button></td></form></tr><?php endforeach?></tbody></table></div></div>
